import './App.css';
import Navbar from './components/navbar';
import Slider from './components/carousal'
import Card from './components/card';
import {BrowserRouter as Router,Route,Switch} from "react-router-dom"

function App() {
  return (
    <Router>
    <div className="App">
      < Navbar />
      Switch
      < Slider />
     < Card />
    </div>
    </Router>
  );
}

export default App;
